import { Type } from "@google/genai";
import { generateWithSchema, analyzeImage } from '../geminiClient';
import { GeneratorOptions, AlgorithmData } from '../../types';
import { getStudentContextPrompt, PEDAGOGICAL_BASE, IMAGE_GENERATION_GUIDE } from './prompts';

/**
 * Generates an Algorithm Flowchart worksheet.
 * Supports Multimodal analysis using gemini-3-flash-preview.
 */
export const generateAlgorithmGeneratorFromAI = async (options: GeneratorOptions): Promise<AlgorithmData[]> => {
    const { topic, difficulty, worksheetCount, studentContext, customInput } = options;

    // Check if we have an image to clone from (Multimodal Mode)
    const sourceImage = typeof customInput === 'string' && customInput.startsWith('data:image') ? customInput : null;

    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${getStudentContextPrompt(studentContext)}

    KONU: "${topic || 'Günlük Hayat Mantığı'}"
    ZORLUK: ${difficulty}

    ${sourceImage ? '[ÖNEMLİ]: Ekteki görseldeki mantıksal akış şemasını ve problem çözüm adımlarını analiz et. Bu mantığı kullanarak tamamen yeni verilerle disleksi dostu bir algoritma üret.' : 'Yeni bir problem senaryosu üzerinden sıralı mantık algoritması üret.'}

    TASARIM KURALLARI:
    - Bir problem senaryosu (challenge) belirle.
    - Adım adım bir çözüm süreci tasarla (Min 5, Max 8 adım).
    - Mutlaka bir karar noktası (decision) ekle.

    ADIM TİPLERİ:
    - 'start': Başlangıç
    - 'process': Eylem adımı
    - 'decision': Koşullu ayrım (Evet/Hayır)
    - 'input': Bilgi girişi
    - 'output': Bilgi çıkışı
    - 'end': Sonuç

    ${IMAGE_GENERATION_GUIDE}

    ÇIKTI: JSON formatında bir dizi (array).
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                imagePrompt: { type: Type.STRING },
                challenge: { type: Type.STRING },
                steps: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.INTEGER },
                            type: { type: Type.STRING, enum: ['start', 'process', 'decision', 'input', 'output', 'end'] },
                            text: { type: Type.STRING }
                        },
                        required: ['id', 'type', 'text']
                    }
                }
            },
            required: ['title', 'steps', 'challenge']
        }
    };

    if (sourceImage) {
        // Use multimodal vision if image provided
        const result = await analyzeImage(sourceImage, prompt, schema, 'gemini-3-flash-preview');
        return Array.isArray(result) ? result : [result];
    }

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

import { Type } from "@google/genai";
import { generateWithSchema, analyzeImage } from '../geminiClient';
import { GeneratorOptions, MapInstructionData, ActivityType } from '../../types';
import { PEDAGOGICAL_BASE, IMAGE_GENERATION_GUIDE, getStudentContextPrompt } from './prompts';

/**
 * AI WORKSHEET CONVERTER (DESIGN CLONER)
 * Analyzes an image and generates a variation with the same architecture but fresh content.
 */
export const generateAiWorksheetConverterFromAI = async (options: GeneratorOptions): Promise<any> => {
    const { topic, difficulty, studentContext, customInput } = options;

    if (!customInput || !customInput.startsWith('data:image')) {
        throw new Error("Dönüştürme işlemi için bir görsel (JPG/PNG) yüklenmesi zorunludur.");
    }

    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${getStudentContextPrompt(studentContext)}

    GÖREV: Ekteki çalışma sayfasını analiz et ve "DİJİTAL İKİZ" bir varyasyon üret.

    ANALİZ KRİTERLERİ:
    1. Görsel Mimariyi (Layout) belirle: Sütunlar, tablolar, eşleştirme alanları vb.
    2. Soru Mantığını anla: Ne tür bir bilişsel beceri ölçülüyor?
    3. YENİ İÇERİK ÜRET: Orijinaldeki kelimeleri, sayıları veya cümleleri KESİNLİKLE kullanma. Tamamen yeni ve özgün veriler üret.

    ZORLUK: ${difficulty}

    ÇIKTI: 'sections' dizisi içeren zengin bir veri yapısı döndür. 
    Her section; 'type' (text|list|grid|matching), 'title', 'content' veya 'items' içermeli.
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            sections: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        type: { type: Type.STRING, enum: ['text', 'image', 'list', 'grid', 'matching'] },
                        title: { type: Type.STRING },
                        content: { type: Type.STRING },
                        items: { type: Type.ARRAY, items: { type: Type.STRING } },
                        gridData: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } }
                    },
                    required: ['type']
                }
            }
        },
        required: ['title', 'instruction', 'sections']
    };

    const result = await analyzeImage(customInput, prompt, schema, 'gemini-3-flash-preview');
    return Array.isArray(result) ? result : [result];
};

export const generateMapInstructionFromAI = async (options: GeneratorOptions): Promise<MapInstructionData[]> => {
    const { worksheetCount, difficulty, studentContext, mapInstructionTypes, emphasizedRegion, itemCount, showCityNames, markerStyle } = options;

    const typesDesc = mapInstructionTypes?.join(', ') || 'Konum Mantığı, Harf Özellikleri, Coğrafi Özellikler';
    const regionDesc = emphasizedRegion === 'all' ? 'Tüm Türkiye' : `${emphasizedRegion} Bölgesi`;

    const prompt = `
    [ROL: KIDEMLİ COĞRAFYA VE ÖZEL EĞİTİM UZMANI]
    ${getStudentContextPrompt(studentContext)}
    "Harita Dedektifi" (Türkiye Coğrafyası ve Yönerge Takibi) etkinliği oluştur.

    ZORUNLU KRİTERLER:
    - ODAK BÖLGE: ${regionDesc}. SADECE bu bölgedeki illeri temel al. 
    - YÖNERGE TİPLERİ: ${typesDesc} kategorilerinden karma sorular hazırla.
    - ADET: Her sayfa için tam ${itemCount || 8} adet yönerge üret.
    - ZORLUK: ${difficulty}. 

    ÇIKTI FORMATI:
    - title: "Harita Dedektifi: ${regionDesc}"
    - instructions: [SADECE string dizi]

    SADECE JSON DÖNDÜR.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                instructions: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['title', 'instruction', 'instructions']
        }
    };

    const raw = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview') as any[];

    const { generateOfflineMapInstruction } = await import('../offlineGenerators/mapDetective');
    const base = await generateOfflineMapInstruction({ ...options, worksheetCount: 1 });

    return raw.map((item: any) => ({
        ...item,
        cities: base[0].cities,
        settings: { 
            showCityNames: showCityNames ?? true, 
            markerStyle: markerStyle ?? 'circle', 
            difficulty 
        }
    }));
};

import React from 'react';
import { AlgorithmData, AlgorithmStep } from '../../types';
import { PedagogicalHeader } from './common';
import { EditableElement, EditableText } from '../Editable';

const StepIcon = ({ type }: { type: string }) => {
    switch (type) {
        case 'start': return <i className="fa-solid fa-circle-play text-emerald-500"></i>;
        case 'end': return <i className="fa-solid fa-circle-stop text-rose-500"></i>;
        case 'decision': return <i className="fa-solid fa-code-branch text-amber-500"></i>;
        case 'process': return <i className="fa-solid fa-gears text-indigo-500"></i>;
        case 'input': return <i className="fa-solid fa-right-to-bracket text-blue-500"></i>;
        case 'output': return <i className="fa-solid fa-right-from-bracket text-purple-500"></i>;
        default: return <i className="fa-solid fa-arrow-right text-zinc-400"></i>;
    }
};

const FlowStep: React.FC<{ step: AlgorithmStep }> = ({ step }) => {
    const baseClass = "p-6 border-[3px] rounded-3xl flex items-center gap-6 shadow-sm min-h-[90px] transition-all relative w-full";
    let typeClass = "border-zinc-800 bg-white";

    if (step.type === 'start') typeClass = "border-emerald-600 bg-emerald-50 font-black uppercase text-emerald-800 rounded-full ring-8 ring-emerald-100/50";
    if (step.type === 'end') typeClass = "border-rose-600 bg-rose-50 font-black uppercase text-rose-800 rounded-full ring-8 ring-rose-100/50";
    if (step.type === 'decision') typeClass = "border-amber-500 bg-amber-50 rounded-[3rem] shadow-amber-100";
    if (step.type === 'input' || step.type === 'output') typeClass = "border-indigo-400 bg-indigo-50/30 italic";
    if (step.type === 'process') typeClass = "border-zinc-900 bg-white font-bold";

    return (
        <EditableElement className={`${baseClass} ${typeClass}`}>
            <div className="w-14 h-14 rounded-2xl bg-white flex items-center justify-center shrink-0 shadow-md border border-zinc-100 text-xl">
                <StepIcon type={step.type} />
            </div>
            <div className="flex-1">
                {step.type === 'decision' && <span className="text-[10px] font-black text-amber-600 uppercase tracking-[0.2em] block mb-1">KARAR NOKTASI</span>}
                <p className="text-base md:text-lg font-black text-zinc-900 leading-tight"><EditableText value={step.text} tag="span" /></p>
            </div>

            {step.type === 'decision' && (
                <div className="flex gap-16 absolute -bottom-14 left-1/2 -translate-x-1/2 z-10">
                    <div className="flex flex-col items-center">
                        <div className="w-0.5 h-10 bg-amber-500"></div>
                        <span className="bg-emerald-600 text-white px-5 py-1.5 rounded-2xl text-[10px] font-black shadow-lg border-2 border-white uppercase tracking-widest">EVET</span>
                    </div>
                    <div className="flex flex-col items-center">
                        <div className="w-0.5 h-10 bg-amber-500"></div>
                        <span className="bg-rose-600 text-white px-5 py-1.5 rounded-2xl text-[10px] font-black shadow-lg border-2 border-white uppercase tracking-widest">HAYIR</span>
                    </div>
                </div>
            )}
        </EditableElement>
    );
};

