                                {/* Simetri Ekseni (Kritik Vurgu) */}
                                {axis === 'vertical' ? (
                                    <line x1={(gridDim / 2) * cellSize} y1="-15" x2={(gridDim / 2) * cellSize} y2={totalSize + 15} stroke="#f43f5e" strokeWidth="5" strokeDasharray="10,5" className="drop-shadow-md" />
