                                    <line x1="-15" y1={(gridDim / 2) * cellSize} x2={totalSize + 15} y2={(gridDim / 2) * cellSize} stroke="#f43f5e" strokeWidth="5" strokeDasharray="10,5" className="drop-shadow-md" />
                                )}
