                    </div>

                    {/* Klinik Yönergeler Alt Bilgi */}
                    <div className="mt-8 flex justify-center gap-12 opacity-50">
                        <div className="flex flex-col items-center">
                            <i className="fa-solid fa-compass-drafting text-2xl text-zinc-400 mb-1"></i>
