export const GridDrawingSheet: React.FC<{ data: GridDrawingData }> = ({ data }) => {
    const gridDim = data?.gridDim || 6;
    const drawingsCount = data?.drawings?.length || 1;

    const maxGridWidth = 350; 
    const maxGridHeight = drawingsCount === 1 ? 700 : (700 / drawingsCount) - 50;

    const cellSize = Math.min(50, Math.floor(maxGridWidth / gridDim), Math.floor(maxGridHeight / gridDim));
    const totalSize = gridDim * cellSize;
    const showCoords = data?.showCoordinates;
    const offset = showCoords ? 30 : 5;

    const renderGrid = (lines: [number, number][][] | null, label: string, isReference: boolean) => {
        // Sanitize label to prevent invalid CSS selector in url(#...)
        const sanitizedId = `pattern-${isReference}-${label.replace(/[^a-z0-9]/gi, '-')}`;

        return (
            <div className="flex flex-col items-center group/grid">
                <div className={`mb-4 px-5 py-2 rounded-2xl border-2 font-black text-[10px] uppercase tracking-widest transition-all shadow-sm ${isReference ? 'bg-indigo-600 text-white border-indigo-700' : 'bg-zinc-100 text-zinc-500 border-zinc-200'}`}>
                    {label}
                </div>
                <div className={`relative p-3 bg-white border-[5px] border-zinc-900 shadow-2xl rounded-3xl overflow-visible transition-all duration-500 ${isReference ? 'ring-8 ring-indigo-50' : 'ring-8 ring-zinc-50'}`}>
                    <svg width={totalSize + offset + 10} height={totalSize + offset + 10} className="overflow-visible">
                        <defs>
                            <pattern id={sanitizedId} width={cellSize} height={cellSize} patternUnits="userSpaceOnUse">
                                {/* fill="none" ensures transparent background within squares */}
                                <rect width={cellSize} height={cellSize} fill="none" stroke="#e2e8f0" strokeWidth="1" />
                            </pattern>
                        </defs>
                        {/* The pattern-filled rect represents the grid lines */}
                        <rect x={offset} y={offset} width={totalSize} height={totalSize} fill={`url(#${sanitizedId})`} />

                        {showCoords && (
                            <g>
                                {Array.from({ length: gridDim + 1 }).map((_, i) => (
                                    <React.Fragment key={i}>
                                        <text x={i * cellSize + offset} y={offset - 12} textAnchor="middle" fontSize="11" fontWeight="900" className="fill-zinc-400 font-mono">{String.fromCharCode(65 + i)}</text>
                                        <text x={offset - 12} y={i * cellSize + offset} dominantBaseline="middle" textAnchor="end" fontSize="11" fontWeight="900" className="fill-zinc-400 font-mono">{i + 1}</text>
                                    </React.Fragment>
                                ))}
                            </g>
                        )}

                        <g transform={`translate(${offset}, ${offset})`}>
                            {Array.from({ length: (gridDim + 1) * (gridDim + 1) }).map((_, i) => {
                                const r = Math.floor(i / (gridDim + 1));
                                const c = i % (gridDim + 1);
                                return (
                                    <circle 
                                        key={i} 
                                        cx={c * cellSize} cy={r * cellSize} 
                                        r={cellSize > 35 ? "3.5" : "2.5"} 
                                        className={`${isReference ? "fill-indigo-400" : "fill-zinc-300"}`} 
                                    />
                                );
                            })}

                            {(lines || []).map((line, index) => {
                                if (!line || line.length < 2) return null;
                                return (
                                    <g key={index}>
                                        <line
                                            x1={line[0][0] * cellSize} y1={line[0][1] * cellSize}
                                            x2={line[1][0] * cellSize} y2={line[1][1] * cellSize}
                                            stroke="#0f172a"
                                            strokeWidth={cellSize > 35 ? "6" : "4"}
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            fill="none"
                                            className="drop-shadow-sm"
                                        />
                                        {index === 0 && (
                                            <circle cx={line[0][0] * cellSize} cy={line[0][1] * cellSize} r="5" fill="#10b981" stroke="white" strokeWidth="2" />
                                        )}
                                        {index === lines.length - 1 && (
                                            <circle cx={line[1][0] * cellSize} cy={line[1][1] * cellSize} r="5" fill="#f43f5e" stroke="white" strokeWidth="2" />
                                        )}
                                    </g>
                                );
                            })}
                        </g>
                    </svg>
                </div>
            </div>
        );
    };

    const getTransformLabel = (mode: string) => {
        switch(mode) {
            case 'mirror_v': return 'DİKEY SİMETRİ';
            case 'mirror_h': return 'YATAY SİMETRİ';
            case 'rotate_90': return '90° DÖNÜŞ';
            case 'rotate_180': return '180° TERS';
            default: return 'KOPYALAMA';
        }
    }

    return (
        <div className="flex flex-col h-full bg-white p-2">
            <PedagogicalHeader title={data?.title} instruction={data?.instruction} note={data?.pedagogicalNote} />

            <div className="flex-1 flex flex-col gap-16 py-8 items-center justify-center">
                {(data?.drawings || []).map((drawing, index) => (
                    <EditableElement key={index} className="flex flex-col md:flex-row gap-12 md:gap-20 items-center justify-center p-12 bg-zinc-50/30 rounded-[4rem] border-2 border-zinc-100 break-inside-avoid relative overflow-hidden group shadow-inner w-full">
                        <div className="absolute top-0 right-0 p-10 opacity-[0.02] pointer-events-none transform rotate-12"><i className="fa-solid fa-compass-drafting text-[15rem]"></i></div>

                        {renderGrid(drawing.lines, `ÖRNEK DESEN ${index + 1}`, true)}

                        <div className="flex flex-row md:flex-col items-center justify-center gap-6 text-zinc-300">
                             <div className="w-16 h-16 rounded-2xl border-[3px] border-zinc-200 flex items-center justify-center text-3xl font-black shadow-md bg-white">
                                 <i className="fa-solid fa-wand-magic-sparkles text-indigo-500 animate-pulse"></i>
                             </div>
                             <div className="bg-indigo-600 text-white px-5 py-2 rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-xl ring-4 ring-indigo-50">
                                 {getTransformLabel(data.transformMode)}
                             </div>
                             <i className="fa-solid fa-arrow-right md:rotate-0 rotate-90 text-4xl text-zinc-200 group-hover:text-indigo-400 transition-colors duration-500"></i>
                        </div>

                        {renderGrid(null, `ÇİZİM ALANI ${index + 1}`, false)}
                    </EditableElement>
                ))}
            </div>

            <div className="mt-auto pt-8 flex justify-between items-center px-12 border-t-2 border-zinc-100">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Metodoloji</span>
                    <span className="text-[12px] font-bold text-zinc-800">CRA (Somuttan Soyuta) Model</span>
                </div>
                <div className="flex flex-col items-center">
                    <div className="flex gap-2 mb-2">
                        <span className="w-2.5 h-2.5 rounded-full bg-emerald-500" title="Başlangıç"></span>
                        <span className="w-2.5 h-2.5 rounded-full bg-rose-500" title="Bitiş"></span>
                    </div>
                    <span className="text-[8px] font-black text-zinc-400 uppercase tracking-[0.2em]">Yön Göstergeleri</span>
                </div>
                <p className="text-[9px] text-zinc-300 font-bold uppercase tracking-[0.5em]">Bursa Disleksi AI • Görsel-Uzamsal Atölye</p>
            </div>
        </div>
    );
};

