export const GridDrawingSheet: React.FC<{ data: GridDrawingData }> = ({ data }) => {
    const gridDim = data?.gridDim || 6;
    const drawingsCount = data?.drawings?.length || 1;

    // A4 Portrait safe width: ~754px.
    // 2 grids side by side with ~2cm (75px) gap.
    const maxGridWidth = 330; 
    const maxGridHeight = drawingsCount === 1 ? 700 : (700 / drawingsCount) - 50;

    const cellSize = Math.min(48, Math.floor(maxGridWidth / gridDim), Math.floor(maxGridHeight / gridDim));
    const totalSize = gridDim * cellSize;
    const showCoords = data?.showCoordinates;
    const offset = showCoords ? 30 : 5;

    const renderGrid = (lines: [number, number][][] | null, label: string, isReference: boolean) => {
        const sanitizedId = `pattern-${isReference}-${label.replace(/[^a-z0-9]/gi, '-')}`;

        return (
            <div className="flex flex-col items-center">
                <div className={`mb-3 px-5 py-1.5 rounded-2xl border-2 font-black text-[9px] uppercase tracking-widest transition-all shadow-sm ${isReference ? 'bg-zinc-900 text-white border-zinc-900' : 'bg-zinc-50 text-zinc-500 border-zinc-200'}`}>
                    {label}
                </div>
                <div className={`relative p-2 bg-white border-[4px] border-zinc-900 shadow-xl rounded-2xl overflow-visible`}>
                    <svg width={totalSize + offset + 10} height={totalSize + offset + 10} className="overflow-visible">
                        <defs>
                            <pattern id={sanitizedId} width={cellSize} height={cellSize} patternUnits="userSpaceOnUse">
                                <rect width={cellSize} height={cellSize} fill="none" stroke="#e2e8f0" strokeWidth="1" />
                            </pattern>
                        </defs>
                        <rect x={offset} y={offset} width={totalSize} height={totalSize} fill={`url(#${sanitizedId})`} />

                        {showCoords && (
                            <g>
                                {Array.from({ length: gridDim + 1 }).map((_, i) => (
                                    <React.Fragment key={i}>
                                        <text x={i * cellSize + offset} y={offset - 10} textAnchor="middle" fontSize="10" fontWeight="900" className="fill-zinc-400 font-mono">{String.fromCharCode(65 + i)}</text>
                                        <text x={offset - 10} y={i * cellSize + offset} dominantBaseline="middle" textAnchor="end" fontSize="10" fontWeight="900" className="fill-zinc-400 font-mono">{i + 1}</text>
                                    </React.Fragment>
                                ))}
                            </g>
                        )}

                        <g transform={`translate(${offset}, ${offset})`}>
                            {Array.from({ length: (gridDim + 1) * (gridDim + 1) }).map((_, i) => {
                                const r = Math.floor(i / (gridDim + 1));
                                const c = i % (gridDim + 1);
                                return (
                                    <circle 
                                        key={i} 
                                        cx={c * cellSize} cy={r * cellSize} 
                                        r={cellSize > 35 ? "3" : "2"} 
                                        className={`${isReference ? "fill-zinc-800" : "fill-zinc-300"}`} 
                                    />
                                );
                            })}

                            {(lines || []).map((line, index) => {
                                if (!line || line.length < 2) return null;
                                return (
                                    <g key={index}>
                                        <line
                                            x1={line[0][0] * cellSize} y1={line[0][1] * cellSize}
                                            x2={line[1][0] * cellSize} y2={line[1][1] * cellSize}
                                            stroke="#000"
                                            strokeWidth={cellSize > 35 ? "5" : "3.5"}
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            fill="none"
                                        />
                                        {index === 0 && (
                                            <circle cx={line[0][0] * cellSize} cy={line[0][1] * cellSize} r="4" fill="#10b981" stroke="white" strokeWidth="1.5" />
                                        )}
                                        {index === lines.length - 1 && (
                                            <circle cx={line[1][0] * cellSize} cy={line[1][1] * cellSize} r="4" fill="#f43f5e" stroke="white" strokeWidth="1.5" />
                                        )}
                                    </g>
                                );
                            })}
                        </g>
                    </svg>
                </div>
            </div>
        );
    };

    return (
        <div className="flex flex-col h-full bg-white p-2">
            <PedagogicalHeader title={data?.title} instruction={data?.instruction} note={data?.pedagogicalNote} />

            <div className="flex-1 flex flex-col gap-10 py-6 items-center justify-center">
                {(data?.drawings || []).map((drawing, index) => (
                    <EditableElement key={index} className="flex flex-row gap-[75px] items-center justify-center p-8 bg-zinc-50/20 rounded-[3rem] border border-zinc-100 break-inside-avoid relative overflow-hidden group w-full">
                        {renderGrid(drawing.lines, `ÖRNEK`, true)}
                        {renderGrid(null, `ÇİZİM ALANI`, false)}
                    </EditableElement>
                ))}
            </div>

            <div className="mt-auto pt-6 flex justify-between items-center px-10 border-t border-zinc-100">
                <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">Metodoloji</span>
                    <span className="text-[11px] font-bold text-zinc-800">Görsel-Motor Kopyalama</span>
                </div>
                <div className="flex flex-col items-center">
                    <div className="flex gap-2 mb-1">
                        <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                        <span className="w-2 h-2 rounded-full bg-rose-500"></span>
                    </div>
                    <span className="text-[7px] font-black text-zinc-300 uppercase tracking-widest">Yön Göstergeleri</span>
                </div>
                <p className="text-[8px] text-zinc-300 font-bold uppercase tracking-[0.5em]">Bursa Disleksi AI • Uzamsal Laboratuvar</p>
            </div>
        </div>
    );
};

