import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, StoryData, SyllableLadderData } from '../../types';

const PEDAGOGICAL_PROMPT = `
[ROL: UZMAN EĞİTİM MATERYALİ TASARIMCISI]
Hedef Kitle: İlkokul öğrencileri (özellikle Disleksi ve DEHB desteği gerektirenler).
Amaç: Okuduğunu anlama, kelime dağarcığını geliştirme ve yaratıcı düşünmeyi desteklemek.
Tasarım Felsefesi: Metin tek başına yetersizdir. Sayfayı dolduracak etkileşimli görevler (kelime avı, çizim, sorular) olmalıdır.
`;

export const generateStoryComprehensionFromAI = async (options: GeneratorOptions): Promise<StoryData[]> => {
    const { topic, difficulty, worksheetCount } = options;

    const constraints = difficulty === 'Başlangıç' 
        ? '50-80 kelime. Basit cümleler. Somut olaylar.' 
        : difficulty === 'Orta' 
            ? '100-150 kelime. Diyalog içerebilir. Günlük maceralar.' 
            : '200+ kelime. Betimlemeler, sebep-sonuç ilişkileri.';

    const prompt = `
    "${topic}" konusunda, ${difficulty} seviyesinde (${constraints}) özgün bir hikaye yaz.

    EKSTRA GÖREVLER (JSON ÇIKTISINDA ZORUNLU):
    1. **vocabulary:** Hikayeden ${difficulty === 'Başlangıç' ? '3' : '4'} adet "öğrenilmesi gereken" veya "zor" kelime seç ve kısa, çocuk dostu tanımlarını yaz.
    2. **creativeTask:** Öğrencinin hikayeyle ilgili yapabileceği bir çizim veya kısa yazma görevi ver (Örn: "Hikayenin sonunu değiştirerek resmini çiz" veya "Kahramana yeni bir isim bul ve nedenini yaz").
    3. **questions:** 
       - 2 adet Çoktan Seçmeli (4 şıklı).
       - 1 adet Doğru/Yanlış.
       - 1 adet Açık Uçlu (Yorum/Çıkarım).

    GÖRSEL PROMPT: Hikayenin en can alıcı sahnesini betimleyen, çocuklar için uygun, renkli, "storybook illustration" tarzında İngilizce bir prompt yaz.

    ${PEDAGOGICAL_PROMPT}
    ${worksheetCount} adet üret.
    `;

    const singleSchema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            story: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            imagePrompt: { type: Type.STRING },
            mainIdea: { type: Type.STRING },
            characters: { type: Type.ARRAY, items: { type: Type.STRING } },
            setting: { type: Type.STRING },
            vocabulary: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        word: { type: Type.STRING },
                        definition: { type: Type.STRING }
                    },
                    required: ['word', 'definition']
                }
            },
            creativeTask: { type: Type.STRING },
            questions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        type: { type: Type.STRING, enum: ['multiple-choice', 'true-false', 'open-ended'] },
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING }, nullable: true },
                        answer: { type: Type.STRING }, 
                        isTrue: { type: Type.BOOLEAN, nullable: true }
                    },
                    required: ['type', 'question', 'answer']
                }
            }
        },
        required: ['title', 'story', 'imagePrompt', 'mainIdea', 'characters', 'setting', 'questions', 'pedagogicalNote', 'vocabulary', 'creativeTask']
    };

    const schema = { type: Type.ARRAY, items: singleSchema };

    return generateWithSchema(prompt, schema) as Promise<StoryData[]>;
};

export const generateSyllableLadderFromAI = async (options: GeneratorOptions): Promise<SyllableLadderData[]> => {
    const { topic, difficulty, worksheetCount, itemCount = 4 } = options;
    const prompt = `
    "${difficulty}" seviyesinde, "${topic || 'Karışık'}" temalı "Hece Merdiveni" etkinliği üret.

    KURALLAR:
    - ${itemCount} adet farklı kelime seç.
    - Her kelimeyi hiyerarşik olarak hecelerine ayır (Örn: "Ke", "Kedi", "Kediler", "Kedilerimiz").
    - Her kelime için o kelimeyi içeren disleksi dostu kısa bir cümle yaz.
    - Kelimeler zorluk seviyesine tam uygun olsun.

    ${PEDAGOGICAL_PROMPT}
    ${worksheetCount} adet üret.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                ladders: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            targetWord: { type: Type.STRING },
                            steps: { type: Type.ARRAY, items: { type: Type.STRING } },
                            sentence: { type: Type.STRING },
                            imagePrompt: { type: Type.STRING }
                        },
                        required: ['targetWord', 'steps', 'sentence']
                    }
                }
            },
            required: ['title', 'instruction', 'ladders']
        }
    };

    const result = await generateWithSchema(prompt, schema) as any[];
    return result.map(page => ({
        ...page,
        displaySettings: {
            useRainbow: options.variant === 'rainbow',
            useBionic: options.concept === 'bionic',
            ladderStyle: options.visualType || 'stairs'
        }
    }));
};

import { GeneratorOptions, StoryData, StoryCreationPromptData, WordsInStoryData, StoryAnalysisData, StorySequencingData, MissingPartsData, StoryQuestion, SyllableLadderData } from '../../types';
import { shuffle, getRandomItems, getWordsForDifficulty, simpleSyllabify } from './helpers';
import { COHERENT_STORY_TEMPLATES } from '../../data/sentences';

const buildBaseStory = (difficulty: string) => {
    let candidates = COHERENT_STORY_TEMPLATES.filter(t => t.level === difficulty);
    if (candidates.length === 0) candidates = COHERENT_STORY_TEMPLATES;

    const template = getRandomItems(candidates, 1)[0];
    const chosenValues: Record<string, string> = {};
    Object.keys(template.variables).forEach(key => {
        chosenValues[key] = getRandomItems(template.variables[key], 1)[0] as string;
    });

    let title = template.titleTemplate;
    let story = template.textTemplate;
    let imagePrompt = template.imagePromptTemplate;

    Object.keys(chosenValues).forEach(key => {
        const regex = new RegExp(`{${key}}`, 'g');
        title = title.replace(regex, chosenValues[key]);
        story = story.replace(regex, chosenValues[key]);
        imagePrompt = imagePrompt.replace(regex, chosenValues[key]);
    });

    return { title, story, imagePrompt, chosenValues, template };
};

export const generateOfflineSyllableLadder = async (options: GeneratorOptions): Promise<SyllableLadderData[]> => {
    const { worksheetCount, difficulty, topic, itemCount = 4 } = options;
    const pool = getWordsForDifficulty(difficulty, topic);

    return Array.from({ length: worksheetCount }, () => {
        const selectedWords = getRandomItems(pool, itemCount);
        const ladders = selectedWords.map(word => {
            const syllables = simpleSyllabify(word);
            const steps: string[] = [];
            let current = "";
            syllables.forEach(s => {
                current += s;
                steps.push(current);
            });

            return {
                targetWord: word,
                steps: steps,
                sentence: `${word} ile ilgili harika bir gün geçirdik.`,
                imagePrompt: word
            };
        });

        return {
            title: "Hece Merdiveni",
            instruction: "Önce parçaları, sonra bütünü oku. Her basamakta hızlan!",
            pedagogicalNote: "Dekodaj akıcılığı, fonolojik farkındalık ve görsel bütünleme becerilerini destekler.",
            ladders,
            displaySettings: {
                useRainbow: options.variant === 'rainbow',
                useBionic: options.concept === 'bionic',
                ladderStyle: (options.visualType as any) || 'stairs'
            }
        };
    });
};

export const generateOfflineStoryComprehension = async (options: GeneratorOptions): Promise<StoryData[]> => {
    const { worksheetCount, difficulty } = options;
    return Array.from({ length: worksheetCount }, () => {
        const { title, story, imagePrompt, template, chosenValues } = buildBaseStory(difficulty);
        const questions: StoryQuestion[] = template.questions.map((qTemp: any) => {
            let qText = qTemp.q;
            Object.keys(chosenValues).forEach(key => {
                qText = qText.replace(new RegExp(`{${key}}`, 'g'), chosenValues[key]);
            });
            let correctAnswer = qTemp.aKey.startsWith("custom:") ? qTemp.aKey.split("custom:")[1] : chosenValues[qTemp.aKey];
            const distractors = getRandomItems(qTemp.distractors as string[], 3);
            return {
                type: 'multiple-choice',
                question: qText,
                options: shuffle([correctAnswer, ...distractors]),
                answer: correctAnswer
            };
        });
        questions.push({ type: 'true-false', question: `Bu hikaye ${chosenValues['place'] || 'bir yerde'} geçmektedir.`, isTrue: true, answer: 'Doğru' });
        const vocabulary = template.vocabulary || [{ word: "Merak", definition: "Bir şeyi öğrenme isteği." }, { word: "Heyecan", definition: "Coşkulu duygu durumu." }];
        return { title, story, instruction: "Hikayeyi 3 kez oku, yıldızları boya ve soruları cevapla.", pedagogicalNote: "Okuduğunu anlama, kelime bilgisi ve yaratıcı ifade.", imagePrompt, mainIdea: "Dikkatli okuma.", characters: [chosenValues['character']], setting: chosenValues['place'], vocabulary, creativeTask: template.creativeTask || "Hikayenin resmini çiz.", questions };
    });
};

export const generateOfflineStoryCreationPrompt = async (options: GeneratorOptions): Promise<StoryCreationPromptData[]> => {
    const { worksheetCount, difficulty } = options;
    return Array.from({ length: worksheetCount }, () => {
        const { title, imagePrompt, chosenValues } = buildBaseStory(difficulty);
        return { title: `Hikaye Atölyesi: ${title}`, instruction: "Verilen ipuçlarını kullanarak kendi hikayeni oluştur.", pedagogicalNote: "Yaratıcı yazma ve kurgu oluşturma.", imagePrompt, prompt: "Aşağıdaki anahtar kelimeleri kullanarak hikayeyi tamamla.", keywords: Object.values(chosenValues).slice(0, 5), structureHints: { who: chosenValues['character'], where: chosenValues['place'], when: "Bir gün", problem: "Beklenmedik bir olay oldu" } };
    });
};

export const generateOfflineWordsInStory = async (options: GeneratorOptions): Promise<WordsInStoryData[]> => {
    const { worksheetCount, difficulty } = options;
    return Array.from({ length: worksheetCount }, () => {
        const { title, story, imagePrompt, template } = buildBaseStory(difficulty);
        const vocabWork = (template.vocabulary || []).map(v => ({ word: v.word, contextQuestion: `"${v.word}" kelimesi metinde ne anlama geliyor?`, type: 'meaning' as const }));
        return { title: 'Kelime Dedektifi', instruction: "Metni oku ve seçili kelimelerin anlamlarını bul.", pedagogicalNote: "Bağlamdan anlam çıkarma.", imagePrompt, story, vocabWork: vocabWork.length > 0 ? vocabWork : [{word: 'Hikaye', contextQuestion: 'Hikaye nedir?', type: 'meaning'}] };
    });
};

export const generateOfflineStoryAnalysis = async (options: GeneratorOptions): Promise<StoryAnalysisData[]> => {
    const { worksheetCount, difficulty } = options;
    return Array.from({ length: worksheetCount }, () => {
        const { title, story, imagePrompt, chosenValues } = buildBaseStory(difficulty);
        return { title: 'Hikaye Haritası', instruction: "Hikayenin unsurlarını analiz et.", pedagogicalNote: "Hikaye kurgusunu anlama.", imagePrompt, story, storyMap: { characters: chosenValues['character'], setting: chosenValues['place'], problem: "Hikayedeki sorun neydi?", solution: "Sorun nasıl çözüldü?", theme: "Ana fikir nedir?" } };
    });
};

export const generateOfflineStorySequencing = async (options: GeneratorOptions): Promise<StorySequencingData[]> => {
    const { worksheetCount } = options;
    const sequences = [
        { title: "Tohumun Büyümesi", steps: ["Tohumu ektim.", "Suladım.", "Filizlendi.", "Çiçek açtı."], img: "Plant growth" },
        { title: "Kek Yapımı", steps: ["Malzemeleri karıştırdım.", "Kalıba döktüm.", "Fırında pişirdim.", "Dilimleyip yedim."], img: "Baking cake" },
        { title: "Diş Fırçalama", steps: ["Macunu sürdüm.", "Dişlerimi fırçaladım.", "Ağzımı çalkaladım.", "Gülümsedim."], img: "Brushing teeth" }
    ];
    return Array.from({ length: worksheetCount }, () => {
        const seq = getRandomItems(sequences, 1)[0];
        const shuffledPanels = shuffle(seq.steps.map((s, i) => ({ id: `step-${i}`, description: s, order: i + 1, imagePrompt: `${seq.img} step ${i+1}` })));
        return { title: `Olay Sıralama: ${seq.title}`, instruction: "Olayları oluş sırasına göre numaralandır.", pedagogicalNote: "Kronolojik düşünme.", imagePrompt: "Sequencing", prompt: "Doğru sırayı bul.", panels: shuffledPanels, transitionWords: ["Önce", "Sonra", "Daha sonra", "En sonunda"] };
    });
};

export const generateOfflineMissingParts = async (options: GeneratorOptions): Promise<MissingPartsData[]> => {
    const { worksheetCount, difficulty } = options;
    return Array.from({ length: worksheetCount }, () => {
        const { title, story, chosenValues, imagePrompt } = buildBaseStory(difficulty);
        const words = Object.values(chosenValues);
        let maskedStory = story;
        words.forEach(w => { maskedStory = maskedStory.replace(w, "_______"); });
        const parts = maskedStory.split('.').filter(s => s.trim().length > 0).map(s => s.trim() + '.');
        return { title: 'Boşluk Doldurma', instruction: "Hikayedeki boşlukları kutudaki kelimelerle tamamla.", pedagogicalNote: "Cümle tamamlama ve anlamsal bütünlük.", imagePrompt, storyWithBlanks: parts, wordBank: shuffle(words), answers: words };
    });
};

