                            onChange={e => handleChange('topic', e.target.value)}
                            placeholder="Örn: Kek yapımı, Okula hazırlık..."
                            className="w-full p-2 bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-lg text-xs font-bold outline-none focus:border-indigo-500 dark:text-zinc-200"
                        />
                    </div>

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactSlider label="Adım Sayısı" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={5} max={10} icon="fa-list-ol" />
                        <div className="flex flex-col gap-2">
                            <span className="text-[10px] font-bold text-zinc-500 uppercase">Görsel Kaynak (Opsiyonel)</span>
                            <button 
                                onClick={() => fileInputRef.current?.click()}
                                className={`w-full py-2 px-3 rounded-lg border-2 border-dashed text-[10px] font-bold transition-all flex items-center justify-center gap-2 ${uploadedImage ? 'bg-indigo-50 border-indigo-300 text-indigo-700' : 'bg-white border-zinc-200 text-zinc-400 hover:border-indigo-300 hover:text-indigo-500'}`}
                            >
                                <i className={`fa-solid ${uploadedImage ? 'fa-check-circle' : 'fa-camera'}`}></i>
                                {uploadedImage ? 'Mantık Analiz Edilecek' : 'Görselden Klonla'}
                            </button>
                            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                        </div>
                    </div>
                </div>
            );
        }

        // --- SAYISAL MANTIK BİLMECELERİ ---
        if (activity.id === ActivityType.NUMBER_LOGIC_RIDDLES) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="Düşünme Modeli" 
                        value={options.logicModel} 
                        onChange={(v:any) => handleChange('logicModel', v)}
                        options={[
                            { value: 'identity', label: 'Sayı Kimliği (Önerme Bazlı)' },
                            { value: 'exclusion', label: 'Eleme / Dışlama Mantığı' },
                            { value: 'sequence', label: 'Dizi ve Örüntü Çıkarımı' },
                            { value: 'cryptarithmetic', label: 'Şifreli İşlem Çözme' }
                        ]}
                        icon="fa-brain-circuit"
                    />

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactSelect 
                            label="Sayı Evreni" 
                            value={options.numberRange} 
                            onChange={(v:string) => handleChange('numberRange', v)}
                            options={[
                                { value: '1-10', label: 'Tek Basamak (1-10)' },
                                { value: '1-20', label: 'Küçük Onluk (1-20)' },
                                { value: '1-50', label: 'Orta Ölçek (1-50)' },
                                { value: '10-100', label: 'İki Basamak (10-100)' },
                                { value: '100-999', label: 'Üç Basamak (100-999)' }
                            ]}
                            icon="fa-infinity"
                        />
                        <CompactSlider label="İpucu Sayısı" value={options.gridSize || 3} onChange={(v:number) => handleChange('gridSize', v)} min={2} max={6} icon="fa-list-check" />
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <CompactCounter label="Bilmece Adedi" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={1} max={12} icon="fa-hashtag" />
                        <CompactToggleGroup 
                            label="Toplam Hedefi" 
                            selected={options.showSumTarget ? 'on' : 'off'} 
                            onChange={(v: string) => handleChange('showSumTarget', v === 'on')} 
                            options={[{ value: 'on', label: 'AKTİF' }, { value: 'off', label: 'KAPALI' }]} 
                        />
                    </div>
                </div>
            );
        }

        if (activity.id === ActivityType.FIND_THE_DIFFERENCE) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="Ayrıştırma Odak Alanı" 
                        value={options.findDiffType} 
                        onChange={(v:any) => handleChange('findDiffType', v)}
                        options={[
                            { value: 'linguistic', label: 'Dilsel (Ayna Harfler)' },
                            { value: 'numeric', label: 'Sayısal (Benzer Rakamlar)' },
                            { value: 'semantic', label: 'Semantik (Kelime Avı)' },
                            { value: 'pictographic', label: 'Sembolik (Piktogram)' }
                        ]}
                        icon="fa-bullseye"
                    />

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactToggleGroup 
                            label="Fark Belirginliği" 
                            selected={options.distractionLevel} 
                            onChange={(v: string) => handleChange('distractionLevel', v)} 
                            options={[
                                { value: 'low', label: 'BELİRGİN' },
                                { value: 'medium', label: 'ORTA' },
                                { value: 'high', label: 'HASSAS' },
                                { value: 'extreme', label: 'MİKRO' }
                            ]} 
                        />
                        <CompactSlider label="Satır Başı Öğe" value={options.gridSize || 4} onChange={(v:number) => handleChange('gridSize', v)} min={3} max={6} icon="fa-table-cells" />
                    </div>

                    <CompactSlider 
                        label="Görev Adedi (Satır)" 
                        value={options.itemCount} 
                        onChange={(v:number) => handleChange('itemCount', v)} 
                        min={4} max={12} 
                        icon="fa-list-ol" 
                    />
                </div>
            );
        }

        if (activity.id === ActivityType.VISUAL_ODD_ONE_OUT) {
            return (
                <div className="space-y-5">
                    <CompactSelect 
                        label="İçerik Mimarisi" 
                        value={options.visualType} 
                        onChange={(v:any) => handleChange('visualType', v)}
                        options={[
                            { value: 'geometric', label: 'Geometrik Formlar' },
                            { value: 'abstract', label: 'Soyut Desenler' },
                            { value: 'character', label: 'Ayna Harf/Rakam' },
                            { value: 'complex', label: 'Karmaşık Çizgiler' },
                            { value: 'fractal', label: 'Fraktal / Kristal' },
                            { value: 'glint', label: 'Minimalist Glint' }
                        ]}
                        icon="fa-shapes"
                    />

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactToggleGroup 
                            label="Fark Belirginliği (Saliency)" 
                            selected={options.distractionLevel} 
                            onChange={(v: string) => handleChange('distractionLevel', v)} 
                            options={[
                                { value: 'low', label: 'Belirgin' },
                                { value: 'medium', label: 'Orta' },
                                { value: 'high', label: 'Hassas' },
                                { value: 'extreme', label: 'Mikro (Zor)' }
                            ]} 
                        />
                        <CompactSlider label="Satır Başı Öğe" value={options.gridSize || 4} onChange={(v:number) => handleChange('gridSize', v)} min={3} max={20} icon="fa-table-cells" />
                    </div>

                    <CompactCounter label="Toplam Görev (Satır)" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={1} max={15} icon="fa-list" />
                </div>
            );
        }

        if (activity.id === ActivityType.GRID_DRAWING || activity.id === ActivityType.SYMMETRY_DRAWING) {
            const isSymmetry = activity.id === ActivityType.SYMMETRY_DRAWING;
            return (
                <div className="space-y-5">
                    <CompactSlider 
                        label="Izgara Boyutu" 
                        value={options.gridSize || 6} 
                        onChange={(v:number) => handleChange('gridSize', v)} 
                        min={3} max={12} icon="fa-border-all" unit="x" 
                    />

                    {!isSymmetry && (
                        <CompactSelect 
                            label="Dönüşüm Modu" 
                            value={options.concept || 'copy'} 
                            onChange={(v:any) => handleChange('concept', v)}
                            options={[
                                { value: 'copy', label: 'Birebir Kopyalama' },
                                { value: 'mirror_v', label: 'Dikey Simetri (Ayna)' },
                                { value: 'mirror_h', label: 'Yatay Simetri' },
                                { value: 'rotate_90', label: '90 Derece Rotasyon' },
                                { value: 'rotate_180', label: '180 Derece Rotasyon' }
                            ]}
                            icon="fa-arrows-spin"
                        />
                    )}

                    {isSymmetry && (
                        <CompactToggleGroup 
                            label="Simetri Ekseni" 
                            selected={options.visualType || 'vertical'} 
                            onChange={(v: string) => handleChange('visualType', v)} 
                            options={[{ value: 'vertical', label: 'DİKEY' }, { value: 'horizontal', label: 'YATAY' }]} 
                        />
                    )}

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactToggleGroup 
                            label="Koordinat Sistemi" 
                            selected={options.useSearch ? 'on' : 'off'} 
                            onChange={(v: string) => handleChange('showCoords', v === 'on')} 
                            options={[{ value: 'on', label: 'GÖSTER' }, { value: 'off', label: 'GİZLE' }]} 
                        />
                        <CompactSlider label="Desen Karmaşıklığı" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={2} max={10} icon="fa-wand-magic-sparkles" />
                    </div>
                </div>
            );
        }

        if (activity.id === ActivityType.HIDDEN_PASSWORD_GRID) {
            return (
                <div className="space-y-5">
                    <CompactSlider label="Izgara Boyutu" value={options.gridSize || 5} onChange={(v:number) => handleChange('gridSize', v)} min={3} max={6} icon="fa-border-all" unit="x" />
                    <CompactSlider label="Sayfa Başı Blok" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={1} max={12} icon="fa-table-cells" />
                    <CompactSelect label="Hücre Tasarımı" value={options.variant} onChange={(v:string) => handleChange('variant', v)} options={[{ value: 'square', label: 'Keskin Kare' }, { value: 'rounded', label: 'Yumuşak Köşe' }, { value: 'minimal', label: 'Sadece Çizgi' }]} icon="fa-palette" />
                    <CompactToggleGroup label="Harf Tipi" selected={options.case} onChange={(v: string) => handleChange('case', v)} options={[{ value: 'upper', label: 'BÜYÜK' }, { value: 'lower', label: 'küçük' }]} />
                </div>
            );
        }

        return null;
    };

    return (
        <div className="flex flex-col h-full bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 shadow-xl overflow-hidden w-full transition-all duration-300">
            <div className="px-4 py-3 border-b border-zinc-200 dark:border-zinc-800 bg-zinc-50/50 dark:bg-zinc-900/50 backdrop-blur-sm shrink-0 flex items-center justify-between z-10 h-[60px]">
                <div className="flex items-center gap-3">
                    <button onClick={onBack} className="w-8 h-8 rounded-full hover:bg-zinc-200 dark:hover:bg-zinc-800 flex items-center justify-center text-zinc-500 transition-colors"><i className="fa-solid fa-arrow-left"></i></button>
                    <h3 className="font-bold text-sm dark:text-white truncate max-w-[150px]">{activity.title}</h3>
                </div>
                {isLoading && <i className="fa-solid fa-circle-notch fa-spin text-indigo-500"></i>}
            </div>

            <div className={`flex-1 overflow-y-auto p-4 custom-scrollbar min-h-0 transition-opacity duration-200 ${isExpanded ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                {/* 1. KISIM: ÖĞRENCİ SEÇİMİ (ZORUNLU) */}
                <div className="mb-6 p-4 bg-amber-50 dark:bg-amber-900/10 rounded-[1.5rem] border border-amber-100 dark:border-amber-800/30">
                    <h4 className="text-[10px] font-black text-amber-600 dark:text-amber-500 uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
                        <i className="fa-solid fa-user-graduate"></i> Aktif Öğrenci
                    </h4>
                    <select 
                        value={activeStudent?.id || "anonymous"}
                        onChange={(e) => handleStudentChange(e.target.value)}
                        className="w-full p-2.5 bg-white dark:bg-zinc-800 border border-amber-200 dark:border-amber-700 rounded-xl text-xs font-bold outline-none focus:ring-2 ring-amber-500/20"
                    >
                        <option value="anonymous">Misafir / Atanmamış</option>
                        {students.map(s => <option key={s.id} value={s.id}>{s.name} ({s.grade})</option>)}
                    </select>
                    <p className="text-[9px] text-amber-500 mt-2 italic font-medium leading-tight">
                        * İçerikler öğrencinin tanısına ve gelişim ihtiyacına göre otomatik uyarlanır.
                    </p>
                </div>

                <div className="grid grid-cols-2 gap-3 mb-6">
                    <CompactCounter label="Sayfa" value={options.worksheetCount} onChange={(v: number) => handleChange('worksheetCount', v)} min={1} max={10} icon="fa-copy" />
                    <div className="col-span-1">
                        <CompactSelect label="Zorluk" value={options.difficulty} onChange={(v: string) => handleChange('difficulty', v)} options={DIFFICULTY_OPTIONS} icon="fa-gauge-high" />
                    </div>
                </div>

                <div className="border-t border-zinc-100 dark:border-zinc-700 pt-4 mb-4">
                    <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-4">Etkinlik Ayarları</h4>
                    {renderActivityControls()}
                </div>

                <div className="mt-8 space-y-3">
                    <button 
                        onClick={() => onGenerate({ ...options, mode: 'fast' })}
                        disabled={isLoading || (activity.id === ActivityType.AI_WORKSHEET_CONVERTER)}
                        className={`w-full py-3 bg-zinc-100 dark:bg-zinc-800 hover:bg-zinc-200 dark:hover:bg-zinc-700 text-zinc-800 dark:text-zinc-200 rounded-xl font-bold text-xs transition-all flex items-center justify-center gap-2 border border-zinc-200 dark:border-zinc-700 ${activity.id === ActivityType.AI_WORKSHEET_CONVERTER ? 'hidden' : ''}`}
                    >
                        <i className="fa-solid fa-bolt"></i> Hızlı Üret (Offline)
                    </button>
                    <button 
                        onClick={() => onGenerate({ ...options, mode: 'ai' })}
                        disabled={isLoading}
                        className="px-4 py-3.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-xs shadow-lg shadow-indigo-500/20 transition-all flex items-center justify-center gap-2 transform active:scale-95"
                    >
                        <i className="fa-solid fa-wand-magic-sparkles"></i> AI ile Üret (Online)
                    </button>
                </div>
            </div>
        </div>
    );
};

import React from 'react';
import { ActivityType, SingleWorksheetData } from '../types';
import * as MathLogic from './sheets/MathLogicSheets';
import * as Memory from './sheets/MemoryAttentionSheets';
import * as Reading from './sheets/ReadingComprehensionSheets';
import * as Dyslexia from './sheets/DyslexiaSupportSheets';
import * as WordGames from './sheets/WordGameSheets';
import * as Visual from './sheets/VisualPerceptionSheets';
import * as Dyscalculia from './sheets/DyscalculiaSheets';
import * as NewActivities from './sheets/NewActivitySheets';
import { AlgorithmSheet } from './sheets/AlgorithmSheets';
import { MapDetectiveSheet } from './sheets/MapDetectiveSheet'; 
import { NumberLogicRiddleSheet } from './sheets/NumberLogicRiddleSheet';
import { ReadingStudioContentRenderer } from './ReadingStudio/ReadingStudioContentRenderer';
import { ImageDisplay, PedagogicalHeader } from './sheets/common';
import { EditableText, EditableElement } from './Editable';

interface SheetRendererProps {
    activityType: ActivityType;
    data: SingleWorksheetData;
}

const RichContentRenderer = ({ data }: { data: any }) => {
    return (
        <div className="space-y-10 w-full animate-in fade-in duration-700">
            <PedagogicalHeader 
                title={data.title} 
                instruction={data.instruction} 
                note={data.pedagogicalNote} 
                data={data}
            />

            <div className="flex flex-col gap-8">
                {(data.sections || []).map((section: any, idx: number) => {
                    const isGrid = section.type === 'grid';
                    const isMatching = section.type === 'matching';
                    const isText = section.type === 'text';

                    return (
                        <EditableElement key={idx} className={`bg-white rounded-[2.5rem] border-2 border-zinc-100 shadow-sm w-full relative overflow-hidden group hover:border-indigo-200 transition-all ${isText ? 'p-8' : 'p-6'}`}>
                            {section.title && (
                                <h4 className="text-xs font-black text-indigo-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2 border-b border-indigo-50 pb-2">
                                    <i className={`fa-solid ${isGrid ? 'fa-table-cells' : isMatching ? 'fa-arrows-left-right' : 'fa-align-left'}`}></i>
                                    <EditableText value={section.title} tag="span" />
                                </h4>
                            )}

                            {section.type === 'text' && (
                                <div className="prose max-w-none text-zinc-800 leading-relaxed font-dyslexic text-lg text-justify">
                                    <EditableText value={section.content} tag="div" />
                                </div>
                            )}

                            {section.type === 'image' && (
                                <div className="w-full h-72 bg-zinc-50 rounded-3xl overflow-hidden my-4 border border-zinc-100">
                                    <ImageDisplay prompt={section.content} description={section.title} className="w-full h-full" />
                                </div>
                            )}

                            {section.type === 'list' && (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {(section.items || []).map((item: string, i: number) => (
                                        <div key={i} className="flex gap-4 items-start p-4 bg-zinc-50 rounded-2xl border border-zinc-100">
                                            <div className="w-6 h-6 rounded-lg bg-zinc-900 text-white flex items-center justify-center text-[10px] font-black shrink-0">{i+1}</div>
                                            <div className="flex-1 font-medium text-zinc-800"><EditableText value={item} tag="span" /></div>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {section.type === 'grid' && (
                                <div className="overflow-x-auto">
                                    <table className="w-full border-collapse">
                                        {section.columnLabels && (
                                            <thead>
                                                <tr>
                                                    {section.columnLabels.map((label: string, i: number) => (
                                                        <th key={i} className="p-3 bg-zinc-900 text-white text-[10px] font-black uppercase tracking-widest border border-zinc-800">
                                                            {label}
                                                        </th>
                                                    ))}
                                                </tr>
                                            </thead>
                                        )}
                                        <tbody>
                                            {(section.gridData || section.items?.map((it:any)=>[it]) || []).map((row: string[], rIdx: number) => (
                                                <tr key={rIdx}>
                                                    {row.map((cell, cIdx) => (
                                                        <td key={cIdx} className="p-4 border border-zinc-200 text-center font-bold text-sm text-zinc-700 bg-white hover:bg-indigo-50/30 transition-colors">
                                                            <EditableText value={cell} tag="span" />
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}

                            {isMatching && (
                                <div className="flex justify-between gap-12 py-4">
                                    <div className="flex-1 space-y-3">
                                        {(section.items || []).slice(0, Math.ceil(section.items.length/2)).map((item: string, i: number) => (
                                            <div key={i} className="p-3 bg-zinc-50 border-2 border-zinc-100 rounded-xl flex items-center justify-between group/row">
                                                <span className="text-sm font-bold text-zinc-700"><EditableText value={item} tag="span" /></span>
                                                <div className="w-3 h-3 rounded-full bg-zinc-300 group-hover/row:bg-indigo-400 transition-colors"></div>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="flex-1 space-y-3">
                                        {(section.items || []).slice(Math.ceil(section.items.length/2)).map((item: string, i: number) => (
                                            <div key={i} className="p-3 bg-zinc-50 border-2 border-zinc-100 rounded-xl flex items-center gap-3 group/row">
                                                <div className="w-3 h-3 rounded-full bg-zinc-300 group-hover/row:bg-indigo-400 transition-colors"></div>
                                                <span className="text-sm font-bold text-zinc-700"><EditableText value={item} tag="span" /></span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </EditableElement>
                    );
                })}
            </div>

            <div className="pt-10 border-t border-zinc-100 flex justify-between items-center opacity-40">
                <p className="text-[8px] font-black uppercase tracking-[0.4em]">Bursa Disleksi AI • Tasarım Klonlama Modülü v2.0</p>
                <i className="fa-solid fa-wand-magic-sparkles"></i>
            </div>
        </div>
    );
};

export const SheetRenderer = React.memo(({ activityType, data }: SheetRendererProps) => {
    if (!data) return null;

    // Zengin içerik veya OCR sonucu
    if (activityType === ActivityType.AI_WORKSHEET_CONVERTER || activityType === ActivityType.OCR_CONTENT || data.sections) {
        return <RichContentRenderer data={data} />;
    }

    if (activityType === ActivityType.STORY_COMPREHENSION && data.layout) {
        return <ReadingStudioContentRenderer layout={data.layout} storyData={data.storyData} />;
    }

    if (activityType === ActivityType.ALGORITHM_GENERATOR) {
        return <AlgorithmSheet data={data} />;
    }

    switch (activityType) {
        case ActivityType.SYLLABLE_LADDER: return <Reading.SyllableLadderSheet data={data} />;
        case ActivityType.MAP_INSTRUCTION: return <MapDetectiveSheet data={data} />; 
        case ActivityType.HIDDEN_PASSWORD_GRID: return <WordGames.HiddenPasswordGridSheet data={data} />;
        case ActivityType.NUMBER_LOGIC_RIDDLES: return <NumberLogicRiddleSheet data={data} />;
        case ActivityType.REAL_LIFE_MATH_PROBLEMS: return <MathLogic.RealLifeMathProblemsSheet data={data} />;
        case ActivityType.MATH_PUZZLE: return <MathLogic.MathPuzzleSheet data={data} />;
        case ActivityType.NUMBER_PATTERN: return <MathLogic.NumberPatternSheet data={data} />;
        case ActivityType.NUMBER_PYRAMID: return <MathLogic.NumberPyramidSheet data={data} />;
        case ActivityType.NUMBER_SEARCH: return <Memory.NumberSearchSheet data={data} />;
        case ActivityType.CLOCK_READING: return <Dyscalculia.ClockReadingSheet data={data} />;
        case ActivityType.MONEY_COUNTING: return <Dyscalculia.MoneyCountingSheet data={data} />;
        case ActivityType.MATH_MEMORY_CARDS: return <Dyscalculia.MathMemoryCardsSheet data={data} />;
        case ActivityType.STORY_COMPREHENSION: return <Reading.StoryComprehensionSheet data={data} />;
        case ActivityType.STORY_ANALYSIS: return <Reading.StoryAnalysisSheet data={data} />;
        case ActivityType.STORY_CREATION_PROMPT: return <Reading.StoryCreationPromptSheet data={data} />;
        case ActivityType.MISSING_PARTS: return <Reading.MissingPartsSheet data={data} />;
        case ActivityType.READING_FLOW: return <Dyslexia.ReadingFlowSheet data={data} />;
        case ActivityType.PHONOLOGICAL_AWARENESS: return <Dyslexia.PhonologicalAwarenessSheet data={data} />;
        case ActivityType.RAPID_NAMING: return <Dyslexia.RapidNamingSheet data={data} />;
        case ActivityType.LETTER_DISCRIMINATION: return <Dyslexia.LetterDiscriminationSheet data={data} />;
        case ActivityType.MIRROR_LETTERS: return <Dyslexia.MirrorLettersSheet data={data} />;
        case ActivityType.SYLLABLE_TRAIN: return <Dyslexia.SyllableTrainSheet data={data} />;
        case ActivityType.VISUAL_TRACKING_LINES: return <Dyslexia.VisualTrackingLinesSheet data={data} />;
        case ActivityType.BACKWARD_SPELLING: return <Dyslexia.BackwardSpellingSheet data={data} />;
        case ActivityType.CODE_READING: return <Dyslexia.CodeReadingSheet data={data} />;
        case ActivityType.ATTENTION_TO_QUESTION: return <Dyslexia.AttentionToQuestionSheet data={data} />;
        case ActivityType.ATTENTION_DEVELOPMENT: return <Dyslexia.AttentionDevelopmentSheet data={data} />;
