import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, SyllableLadderData } from '../../types';

export const generateSyllableLadderFromAI = async (options: GeneratorOptions): Promise<SyllableLadderData[]> => {
    const { topic, difficulty, worksheetCount, itemCount = 4, variant, concept, visualType } = options;

    const difficultyContext = {
        'Başlangıç': '2-3 heceli, basit, açık heceli kelimeler (kedi, elma, masa).',
        'Orta': '3-4 heceli, kapalı hece içeren kelimeler (arkadaş, pabuçlar).',
        'Zor': '4-5 heceli, konson kümeleri (tr, st, pr) içeren karmaşık kelimeler (strateji, program).',
        'Uzman': '5+ heceli, çok ekli veya teknik terimler (cumhuriyetimiz, teknolojik).'
    }[difficulty as string || 'Orta'];

    const prompt = `
    [ROL: DİSLEKSİ EĞİTİM UZMANI]
    GÖREV: "${difficulty}" seviyesinde "Hece Merdiveni" etkinliği üret.
    TEMA: ${topic || 'Karışık'}
    ZORLUK KRİTERİ: ${difficultyContext}
    ADET: ${itemCount} adet farklı kelime.

    KURALLAR:
    1. Her kelimeyi hiyerarşik olarak bir basamak ekleyerek ayır. 
       Örn (Kelime: Araba): "A", "Ara", "Araba"
       Örn (Kelime: Kitaplık): "Ki", "Kita", "Kitap", "Kitaplık"
    2. Her kelime için o kelimenin geçtiği akıcı, kısa ve disleksi dostu bir "cümle" yaz.
    3. Cümleler kelimenin anlamını pekiştirmeli.

    ÇIKTI (JSON):
    - title: "Hece Merdiveni"
    - instruction: "Önce parçaları, sonra bütünü oku. Yıldızları boyayarak ilerle!"
    - pedagogicalNote: "Segmentasyon ve dekodaj akıcılığını artırmak için tasarlanmıştır."
    - ladders: [{ targetWord, steps: string[], sentence, imagePrompt }]

    ${worksheetCount} sayfa üret.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                ladders: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            targetWord: { type: Type.STRING },
                            steps: { type: Type.ARRAY, items: { type: Type.STRING } },
                            sentence: { type: Type.STRING },
                            imagePrompt: { type: Type.STRING }
                        },
                        required: ['targetWord', 'steps', 'sentence']
                    }
                }
            },
            required: ['title', 'ladders']
        }
    };

    const result = await generateWithSchema(prompt, schema) as any[];
    return result.map(page => ({
        ...page,
        displaySettings: {
            useRainbow: variant === 'rainbow',
            useBionic: concept === 'bionic',
            ladderStyle: visualType || 'center',
            showTracker: true
        }
    }));
};

import { GeneratorOptions, SyllableLadderData } from '../../types';
import { getRandomItems, getWordsForDifficulty, simpleSyllabify } from './helpers';

export const generateOfflineSyllableLadder = async (options: GeneratorOptions): Promise<SyllableLadderData[]> => {
    const { worksheetCount, difficulty, topic, itemCount = 6, variant, concept, visualType } = options;

    const results: SyllableLadderData[] = [];
    const pool = getWordsForDifficulty(difficulty, topic);

    for (let p = 0; p < worksheetCount; p++) {
        const selectedWords = getRandomItems(pool, itemCount);
        const ladders = selectedWords.map(word => {
            const syllables = simpleSyllabify(word);
            const steps: string[] = [];

            // Build ladder steps: K, Ka, Kal, Kale, Kalem
            // Turkish syllable logic approx:
            let currentStr = "";
            for (let i = 0; i < word.length; i++) {
                // Her harf eklendiğinde yeni bir adım (Harf Temelli Merdiven - Daha etkili)
                currentStr += word[i];
                if (currentStr.length > 1) steps.push(currentStr);
            }
            // Ensure last step is the full word
            if (steps[steps.length-1] !== word) steps.push(word);

            // If too many steps (long word), filter to keep it compact
            const finalSteps = steps.length > 6 ? [steps[0], steps[2], steps[4], steps[steps.length-1]] : steps;

            return {
                targetWord: word,
                steps: finalSteps,
                sentence: `${word.charAt(0).toUpperCase() + word.slice(1)} hayatımızın bir parçasıdır.`,
                imagePrompt: word
            };
        });

        results.push({
            title: "Hece Merdiveni",
            instruction: "Basamakları teker teker oku, en sonunda cümleyi bitir.",
            pedagogicalNote: "Parçadan bütüne sentezleme ve okuma hızını artırır.",
            ladders,
            displaySettings: {
                useRainbow: variant === 'rainbow',
                useBionic: concept === 'bionic',
                ladderStyle: (visualType as any) || 'center',
                showTracker: true
            }
        });
    }
    return results;
};

