export const SyllableLadderSheet: React.FC<{ data: SyllableLadderData }> = ({ data }) => {
    const { useRainbow, useBionic, ladderStyle, showTracker } = data.displaySettings;
    const itemsCount = data.ladders?.length || 0;

    // Layout Logic: 1-4 items -> Big Single Column, 5-8 items -> 2 Column Grid
    const isGrid = itemsCount > 4;

    return (
        <div className="flex flex-col h-full bg-white font-lexend text-black">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} />

            <div className={`grid ${isGrid ? 'grid-cols-2 gap-4' : 'grid-cols-1 gap-6'} mt-2 flex-1 content-start`}>
                {(data.ladders || []).map((item, idx) => (
                    <EditableElement 
                        key={idx} 
                        className={`flex flex-col border-[3px] border-zinc-900 rounded-[2.5rem] p-5 bg-white relative overflow-hidden group break-inside-avoid shadow-sm`}
                    >
                        {/* Sayı ve İkon */}
                        <div className="flex justify-between items-start mb-4">
                            <div className="w-8 h-8 bg-zinc-900 text-white rounded-xl flex items-center justify-center font-black text-xs shadow-lg">
                                {idx + 1}
                            </div>
                            {showTracker && (
                                <div className="flex gap-1">
                                    {[1, 2, 3].map(s => (
                                        <div key={s} className="w-5 h-5 rounded-full border-2 border-zinc-200 flex items-center justify-center">
                                            <i className="fa-solid fa-star text-[8px] text-zinc-100"></i>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Merdiven Alanı */}
                        <div className={`flex-1 flex flex-col gap-2 mb-4 ${
                            ladderStyle === 'center' ? 'items-center' : 'items-start'
                        }`}>
                            {(item.steps || []).map((step, sIdx) => (
                                <div 
                                    key={sIdx} 
                                    className="transition-all duration-300"
                                    style={{ 
                                        paddingLeft: ladderStyle === 'stairs' ? `${sIdx * 12}px` : '0',
                                        opacity: 0.4 + (sIdx / item.steps.length) * 0.6
                                    }}
                                >
                                    <div className="bg-zinc-50 px-4 py-1.5 rounded-xl border border-zinc-200 group-hover:border-indigo-400 group-hover:bg-white transition-colors">
