                                            mode={useRainbow ? 'rainbow' : (useBionic ? 'bionic' : 'standard')} 
                                            className="text-base font-black uppercase tracking-widest" 
                                        />
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Cümle Kutusu */}
                        <div className="bg-zinc-900 text-white p-3 rounded-2xl relative shadow-md">
                            <div className="absolute -top-2 left-4 bg-indigo-500 px-2 py-0.5 rounded-full text-[7px] font-black uppercase tracking-widest shadow-sm">OKU VE ANLA</div>
