    expert_words: string[];
    confusing_words: string[][];
    synonyms: { word: string; synonym: string }[];
    antonyms: { word: string; antonym: string }[];
    colors_detailed: { name: string; css: string }[];
    homonyms: string[];
    [key: string]: any;
}

export const TR_VOCAB = RAW_VOCAB as VocabData;

export const turkishAlphabet = 'abcçdefgğhıijklmnoöprsştuüvyz';
export const vowels = 'aeıioöuü';

export const simpleSyllabify = (text: string): string[] => {
    const word = text.toLowerCase().trim();
    if (!word) return [];

    // Kural Tabanlı Türkçe Heceleme Algoritması
    const syllables: string[] = [];
    let currentSyllable = "";
    const chars = word.split("");

    for (let i = chars.length - 1; i >= 0; i--) {
        currentSyllable = chars[i] + currentSyllable;
        const char = chars[i];

        if (vowels.includes(char)) {
            // Eğer ünlüden önce ünsüz varsa onu da al (Hece başı ünsüzü)
            if (i > 0 && !vowels.includes(chars[i - 1])) {
                // Eğer ünsüzden önce bir ünsüz daha varsa ve o da bir ünlüden sonraysa (örn: alt -> al-t değil al-ta)
                // Türkçe'de kelime içinde iki ünlü arasındaki ünsüz sağdaki ünlüyle hece kurar.
                currentSyllable = chars[i - 1] + currentSyllable;
                i--;
            }
            syllables.unshift(currentSyllable);
            currentSyllable = "";
        }
    }

    // Kalan harf varsa (başta ünsüz kalması durumu) ilk heceye ekle
    if (currentSyllable) {
        if (syllables.length > 0) {
            syllables[0] = currentSyllable + syllables[0];
        } else {
            syllables.push(currentSyllable);
        }
    }

    return syllables;
};

export const shuffle = <T>(array: T[]): T[] => {
    const newArray = [...array];
    for (let i = newArray.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
    }
    return newArray;
};

export const getRandomInt = (min: number, max: number): number => Math.floor(Math.random() * (max - min + 1)) + min;

export const getRandomItems = <T>(arr: T[], count: number): T[] => {
    if (!arr || arr.length === 0) return [];
    if (count >= arr.length) return shuffle(arr);
    return shuffle(arr).slice(0, count);
};

export const getWordsForDifficulty = (difficulty: string, topic?: string): string[] => {
    // Kelime hazinesini zenginleştirmek için KNOWLEDGE_BASE ve TR_VOCAB birleştirildi
    let pool: string[] = [];

    if (difficulty === 'Başlangıç') {
        pool = [...TR_VOCAB.easy_words, ...KNOWLEDGE_BASE.animals.filter(w => w.difficulty === 1).map(w => w.text)];
    } else if (difficulty === 'Orta') {
        pool = [...TR_VOCAB.medium_words, ...KNOWLEDGE_BASE.animals.filter(w => w.difficulty <= 2).map(w => w.text)];
    } else if (difficulty === 'Zor') {
        pool = [...TR_VOCAB.hard_words, ...KNOWLEDGE_BASE.abstract.map(w => w.text)];
    } else {
        pool = [...TR_VOCAB.expert_words, "elektromanyetik", "sürdürülebilirlik", "kurumsallaşma"];
    }

    if (topic && TR_VOCAB[topic]) {
        pool = [...pool, ...TR_VOCAB[topic]];
    }

    return shuffle([...new Set(pool)]);
};

import { GeneratorOptions, SyllableLadderData } from '../../types';
import { getRandomItems, getWordsForDifficulty, simpleSyllabify } from './helpers';

export const generateOfflineSyllableLadder = async (options: GeneratorOptions): Promise<SyllableLadderData[]> => {
    const { worksheetCount, difficulty, topic, itemCount = 6, variant, concept, visualType, ladderMode = 'syllable' } = options;

    const results: SyllableLadderData[] = [];
    const pool = getWordsForDifficulty(difficulty, topic);

    for (let p = 0; p < worksheetCount; p++) {
        const selectedWords = getRandomItems(pool, itemCount);
        const ladders = selectedWords.map(word => {
            const steps: string[] = [];

            if (ladderMode === 'letter') {
                // Harf harf birikerek: K, Ka, Kal, Kale
                let current = "";
                for (const char of word) {
                    current += char;
                    if (current.length >= 1) steps.push(current);
                }
            } else {
                // Hece hece birikerek: Ka, Kalem, Kalemlik
                const syllables = simpleSyllabify(word);
                let current = "";
                syllables.forEach(s => {
                    current += s;
                    steps.push(current);
                });
            }

            // Maksimum 6 basamak tut (Görsel kompaktlık için)
            const finalSteps = steps.length > 6 
                ? [steps[0], steps[Math.floor(steps.length/2)], steps[steps.length-2], steps[steps.length-1]] 
                : steps;

            return {
                targetWord: word,
                steps: finalSteps,
                sentence: `${word.charAt(0).toUpperCase() + word.slice(1)} hakkında yeni bir şeyler öğrendim.`,
                imagePrompt: word
            };
        });

        results.push({
            title: "Hece ve Okuma Merdiveni",
            instruction: "Basamakları dikkatle oku. Her adımda bir önceki sesleri hatırla!",
            pedagogicalNote: "Fonolojik farkındalık, hece sentezi ve görsel takip becerilerini geliştirir.",
            ladders,
            displaySettings: {
                useRainbow: variant === 'rainbow',
                useBionic: concept === 'bionic',
                ladderStyle: (visualType as any) || 'center',
                showTracker: true
            }
        });
    }
    return results;
};

