// Fix: Added missing generateMazePath utility
export const generateMazePath = (rows: number, cols: number) => {
    const grid = Array.from({ length: rows }, (_, r) => 
        Array.from({ length: cols }, (_, c) => r * cols + c)
    );
    const pathIds = [];
    for (let r = 0; r < rows; r++) {
        if (r % 2 === 0) {
            for (let c = 0; c < cols; c++) pathIds.push(r * cols + c);
        } else {
            for (let c = cols - 1; c >= 0; c--) pathIds.push(r * cols + c);
        }
    }
    const distractorIds = grid.flat().filter(id => !pathIds.includes(id));
    return { grid, pathIds, distractorIds };
};

