export const generateConnectedPath = (gridSize: number, complexity: number) => {
    const lines: [number, number][][] = [];
    let curr = [Math.floor(Math.random() * gridSize), Math.floor(Math.random() * gridSize)];
    for(let i=0; i<complexity + 2; i++) {
        let next = [Math.floor(Math.random() * gridSize), Math.floor(Math.random() * gridSize)];
        lines.push([curr as [number, number], next as [number, number]]);
        curr = next;
    }
    return lines;
};

