// Internal UI helper for select inputs
const CompactSelect = ({ label, value, onChange, options, icon }: any) => (
    <div className="space-y-1.5">
        <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-1.5">
            <i className={`fa-solid ${icon}`}></i> {label}
        </label>
        <select 
            value={value} 
            onChange={(e) => onChange(e.target.value)}
            className="w-full bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-xl p-2.5 text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500/20 transition-all"
        >
            {options.map((opt: any) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
        </select>
    </div>
);

// Internal UI helper for range inputs
const CompactSlider = ({ label, value, onChange, min, max, icon }: any) => (
    <div className="space-y-1.5">
        <div className="flex justify-between items-center">
            <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest flex items-center gap-1.5">
                <i className={`fa-solid ${icon}`}></i> {label}
            </label>
            <span className="text-xs font-mono font-bold text-indigo-500">{value}</span>
        </div>
        <input 
            type="range" min={min} max={max} value={value} 
            onChange={(e) => onChange(Number(e.target.value))}
            className="w-full h-1.5 bg-zinc-200 dark:bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-indigo-600"
        />
    </div>
);

