import React from 'react';
import { ActivityType } from '../types';
import * as Reading from './sheets/ReadingComprehensionSheets';
import { AlgorithmSheet } from './sheets/AlgorithmSheets';
import { MapDetectiveSheet } from './sheets/MapDetectiveSheet';
import { ReadingStudioContentRenderer } from './ReadingStudio/ReadingStudioContentRenderer';

interface SheetRendererProps {
    activityType: ActivityType;
    data: any;
}

// Simple renderer for AI-converted or OCR structured content
const RichContentRenderer: React.FC<{ data: any }> = ({ data }) => {
    return (
        <div className="space-y-8 p-6">
            {data.sections?.map((section: any, idx: number) => (
                <div key={idx} className="p-6 border-2 border-zinc-100 dark:border-zinc-800 rounded-3xl bg-white dark:bg-zinc-900 shadow-sm break-inside-avoid">
                    {section.title && <h3 className="font-black text-indigo-600 uppercase text-xs tracking-widest mb-4 border-b border-zinc-50 pb-2">{section.title}</h3>}

                    {section.type === 'grid' && section.gridData && (
                        <div className="overflow-x-auto">
                            <table className="w-full border-collapse">
                                <tbody>
                                    {section.gridData.map((row: string[], rIdx: number) => (
                                        <tr key={rIdx}>
                                            {row.map((cell: string, cIdx: number) => (
                                                <td key={cIdx} className="border border-zinc-200 p-3 text-center font-bold text-sm">{cell}</td>
                                            ))}
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}

                    {section.type === 'list' && section.items && (
                        <ul className="space-y-2">
                            {section.items.map((item: string, iIdx: number) => (
                                <li key={iIdx} className="flex gap-3 items-start text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                    <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 shrink-0"></span>
                                    {item}
                                </li>
                            ))}
                        </ul>
                    )}

                    {(section.type === 'text' || !section.type) && section.content && (
                        <p className="text-base text-zinc-800 dark:text-zinc-200 leading-relaxed text-justify">{section.content}</p>
                    )}
                </div>
            ))}
        </div>
    );
};

export const SheetRenderer = React.memo(({ activityType, data }: SheetRendererProps) => {
    if (!data) return null;

    // Handle rich content types (OCR results and direct AI clones)
    if (activityType === ActivityType.AI_WORKSHEET_CONVERTER || activityType === ActivityType.OCR_CONTENT || data.sections) {
        return <RichContentRenderer data={data} />;
    }

    // Reading Studio has its own complex dynamic layout engine
    if (activityType === ActivityType.STORY_COMPREHENSION && data.layout) {
        return <ReadingStudioContentRenderer layout={data.layout} storyData={data.storyData} />;
    }

    // Algorithm flowchart special renderer
    if (activityType === ActivityType.ALGORITHM_GENERATOR) {
        return <AlgorithmSheet data={data} />;
    }

    // Map Detective interactive map renderer
    if (activityType === ActivityType.MAP_INSTRUCTION) {
        return <MapDetectiveSheet data={data} />;
    }

    // Switch case for standard activities with specialized sheet components
    switch (activityType) {
        case ActivityType.READING_STROOP: 
            return <Reading.ReadingStroopSheet data={data} />;

        default: 
            // Fallback UI for activities without a specific renderer yet
            return (
                <div className="flex flex-col items-center justify-center p-20 text-center">
                    <div className="w-20 h-20 bg-zinc-50 dark:bg-zinc-800 rounded-full flex items-center justify-center mb-6 border-2 border-dashed border-zinc-200 dark:border-zinc-700">
                        <i className="fa-solid fa-microchip text-3xl opacity-20 text-zinc-400"></i>
                    </div>
                    <h3 className="text-lg font-black text-zinc-800 dark:text-zinc-100 uppercase tracking-tight">Görselleştirici Hazırlanıyor</h3>
                    <p className="text-xs text-zinc-500 mt-2 max-w-xs mx-auto leading-relaxed">
                        Bu aktivite tipi ({activityType}) için yüksek çözünürlüklü gösterici motoru şu an geliştirme aşamasındadır.
                    </p>
                </div>
            );
    }
});

